-- Balance Sheet Data: Dec 2025 actuals for all properties
-- Run this in Supabase SQL editor

CREATE TABLE IF NOT EXISTS balance_sheet_items (
  id SERIAL PRIMARY KEY,
  property_id TEXT NOT NULL,
  bs_code TEXT NOT NULL,
  account_name TEXT NOT NULL,
  account_type TEXT NOT NULL CHECK (account_type IN ('asset','liability','equity')),
  account_section TEXT NOT NULL,
  is_header BOOLEAN DEFAULT FALSE,
  is_total BOOLEAN DEFAULT FALSE,
  period TEXT NOT NULL DEFAULT '2025-12',
  amount NUMERIC(14,2) DEFAULT 0,
  sort_order INTEGER DEFAULT 0,
  UNIQUE(property_id, bs_code, period)
);

CREATE TABLE IF NOT EXISTS reserve_draws (
  id SERIAL PRIMARY KEY,
  property_id TEXT NOT NULL,
  year INTEGER NOT NULL,
  month INTEGER NOT NULL CHECK (month >= 1 AND month <= 12),
  reserve_type TEXT NOT NULL,
  draw_amount NUMERIC(14,2) DEFAULT 0,
  description TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Enable RLS
ALTER TABLE balance_sheet_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE reserve_draws ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow all for balance_sheet_items" ON balance_sheet_items FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow all for reserve_draws" ON reserve_draws FOR ALL USING (true) WITH CHECK (true);

